VALUES
  ('bookkeeper-moex-00137', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司在X8年1月1日成立，主管機關核准其發行面額$10之普通股45,000股。甲公司X8 年度部分交易如下：⑴1月13日以每股$17 發行5,000股普通股。⑵3月8日以每股$15發 行2,500股普通股。⑶6月28日以每股$12買回1,500股普通股。⑷8月5日以每股$16 發行 1,500股普通股。⑸10月16日以每股$18出售1,000股庫藏股票。甲公司對出售庫藏股票採 先進先出法，若使用成本法處理庫藏股票交易，X8年12月31日的資本公積餘額為多少？', '["$56,500", "$61,500", "$62,500", "$64,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00138', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於 X1 年中買回公司之普通股，購買價格高於普通股之面值及原發行價格，但低於每 股帳面價值。請問此項交易對股東權益的影響為何？', '["股東權益總額提高，每股帳面價值提高", "股東權益總額提高，每股帳面價值降低", "股東權益總額降低，每股帳面價值提高", "股東權益總額降低，每股帳面價值降低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00139', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '乙公司X7年6月30日的股東權益如下： 普通股，面額$10 $3,500,000 資本公積 880,000 保留盈餘 1,000,000 乙公司於X7年7月1日宣告發放5%股票股利，並於7月31日發放，普通股在股利宣告日 的市價為$40，在發放日的市價為$42。關於股票股利之會計處理，乙公司應借記「保留盈餘」 之金額為？', '["$175,000", "$210,000", "$700,000", "$735,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00140', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X2年12月5日調整下列交易前之應付帳款餘額為$350,000：⑴甲公司於X2年12月', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00141', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '日購入商品$165,000，付款條件 2/10，n/30。甲公司採用淨額法記錄應付帳款。該張進貨 發票於X3年1月3日入帳及付款。⑵甲公司向乙公司進貨$60,000，雙方約定起運點交貨， 乙公司於X2年12月26日交運，甲公司於X3年1月6日收到貨品。⑶甲公司於X2年12 月22日訂購貨品一批發票價格為$45,000，雙方約定目的地交貨。該批貨品於X3年1月2日 送達。甲公司X2年12月31日之應付帳款餘額為多少？', '["$556,700", "$571,700", "$575,000", "$616,700"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00142', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X5年銷售一種附有2年保證維修期限之玩具狗，依據公司過去經驗得知有45%玩具 狗不會發生損壞，35%玩具狗會發生小瑕疵，20%玩具狗則會發生重大瑕疵。每隻玩具狗發生 小瑕疵和重大瑕疵時之平均修理費用分別為$120及$400。甲公司X5年度共銷售500隻玩具 狗，每隻售價為$1,500，X5年實際發生的免費維修支出為$25,800。甲公司X5年12月31日 估計產品保證負債餘額為何？', '["$25,800", "$35,200", "$61,000", "$86,800"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00143', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X6年將銷售一款新型產品Z，預估相關資料如下：產品Z單位售價$180，單位變動 成本$140。產品Z的固定成本則包括租金$185,000，折舊費用$110,000，銷售費用$275,000， 管理費用$130,000。甲公司適用的所得稅率為 20%。甲公司 X6 年欲賺得$300,000 之稅後利 潤，應銷售多少單位產品Z？', '["9,375單位", "25,000單位", "26,875單位", "31,250單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00144', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '丁公司債券投資的相關資料如下： 公允價值 成本 X5年底 X6年底 透過損益按公允價值衡量 $400,000 $320,000 $420,000 按攤銷後成本衡量 400,000 330,000 360,000 丁公司X6年綜合損益表的金融資產評價損益為？', '["損失$20,000", "利益$20,000", "利益$100,000", "利益$130,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00145', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '李君為甲公司新進會計人員，正使用間接法來編製現金流量表，X4年相關資料如下：權益法 認列投資收益$66,000，購買一台機器付款$75,000，採權益法之長期股權投資收到股利 $35,000，支付現金股利給股東$40,000，簽發票據$100,000取得一筆土地。甲公司X4年度折 舊費用$20,000。甲公司X4年度存貨增加$18,000，應收帳款淨額減少$27,000，應付帳款減少 $30,000。甲公司 X4 年度淨利$140,000，期初現金餘額$30,000。甲公司 X4 年的營業活動淨 現金流入為多少？', '["$68,000", "$108,000", "$144,000", "$240,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00146', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '丙公司 X6 年 12 月 31 日帳上有零用金$1,000，A 銀行支票存款$25,000，B 銀行存款透支 $5,000，以及顧客償還貨款寄來的郵局匯票$3,200。丙公司若帳上與銀行對帳單沒有任何差異， X6年底資產負債表上的現金餘額為？', '["$1,000", "$24,200", "$26,000", "$29,200"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00147', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '乙公司於X6年7月初以$300,000購入一台機器，估計耐用年限5年，殘值$20,000，使用直 線法提列折舊。X7年底由於經營環境改變使得該機器之價值有重大跡象顯示已經發生減損。 乙公司於X7年底作減損測試，估計該機器之使用價值為$170,000，淨公允價值為$185,000， 估計耐用年限不變。乙公司X7年應認列之減損損失為？', '["$25,000", "$31,000", "$40,000", "$46,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00148', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於 X3 年初登記設立，核准發行普通股 160,000 股，每股面額 $10，該公司將分兩次 發行，第一次於X3年初以每股$30發行 1/2股數，第二次則於X3年底發行剩餘股數。甲公 司 X4年初，帳列「資本公積一普通股溢價」為$3,360,000。甲公司第二次發行普通股時的每股 發行價為何？', '["$21", "$22", "$31", "$32"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00149', 'bookkeeper', 'bookkeeper-moex-113-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '乙公司 X2 年底部分帳戶餘額如下：應付帳款$25,500，長期抵押借款$100,000，估計產品保 證負債$12,000，遞延所得稅負債$15,500，短期借款$22,000，備抵呆帳貸餘$3,500，短期應付 票據$35,000，應付公司債$60,000（4年後到期），累計減損$5,500。乙公司X2年底，資產負 債表上應認列的流動負債金額為？', '["$94,500", "$98,000", "$100,000", "$111,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:18+00:00", "source_pdf_sha1": "d3d8aed0950c", "answer_pdf_sha1": "a40062b9ae71", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
